const headers = $('Webhook - Recibir Solicitud1').first().json.headers || {};
const token = headers['x-g2fit-token'] || headers['X-G2Fit-Token'] || '';
const EXPECTED = 'G2FIT-SEND-a7f3c92d4e8b1';
if (token !== EXPECTED) {
  throw new Error('Unauthorized: token de acceso inválido o ausente. Añade la cabecera X-G2Fit-Token.');
}
return $input.all();

// ===== G2FIT — PDF Visual Profesional =====
const dieta   = $('Supabase - Leer Dieta1').first().json;
const cliente = $('Supabase - Leer Cliente1').first().json;

const plan = typeof dieta.plan_completo === 'string'
  ? JSON.parse(dieta.plan_completo)
  : (dieta.plan_completo || {});

const semana  = (plan.semanas && plan.semanas[0]) || {};
const dias    = semana.dias || plan.plan_semanal || plan.dias || [];
const resumen = plan.resumen_plan || {};

const N = s => (s||'').toString()
  .replace(/[\xE1\xE0\xE2\xE3]/g,'a').replace(/[\xE9\xE8\xEA]/g,'e').replace(/[\xED\xEC\xEE]/g,'i')
  .replace(/[\xF3\xF2\xF4]/g,'o').replace(/[\xFA\xF9\xFB]/g,'u').replace(/\xF1/g,'n')
  .replace(/[\xC1\xC0\xC2\xC3]/g,'A').replace(/[\xC9\xC8\xCA]/g,'E').replace(/[\xCD\xCC\xCE]/g,'I')
  .replace(/[\xD3\xD2\xD4]/g,'O').replace(/[\xDA\xD9\xDB]/g,'U').replace(/\xD1/g,'N')
  .replace(/\xFC/g,'u').replace(/\xDC/g,'U').replace(/[^\x20-\x7E]/g,'?');

const E = s => N(s).replace(/\\/g,'\\\\').replace(/\(/g,'\\(').replace(/\)/g,'\\)');

// Wrap text to lines of maxChars characters
const wrapText = (text, maxChars) => {
  if (!text) return [''];
  const words = text.split(' ');
  const lines = [];
  let line = '';
  for (const w of words) {
    if (line.length + w.length + 1 > maxChars && line) {
      lines.push(line.trim());
      line = w + ' ';
    } else {
      line += w + ' ';
    }
  }
  if (line.trim()) lines.push(line.trim());
  return lines.length ? lines : [''];
};

const LOGO_B64 = '';

const LOGO_W = 180, LOGO_H = 85;
const LOGO_DW = 160, LOGO_DH = 75;

// ===== Colors [R, G, B] 0-1 =====
const NAVY       = [0.059, 0.086, 0.165];
const PINK       = [0.984, 0.373, 0.671];
const LIGHT_PINK = [0.992, 0.902, 0.953];
const LIGHT_BG   = [0.967, 0.967, 0.973];
const GRAY       = [0.39,  0.455, 0.545];
const WHITE      = [1, 1, 1];
const DIVIDER    = [0.859, 0.875, 0.902];

// ===== PDF Page constants =====
const PW = 595.28, PH = 841.89;
const ML = 38, MR = 38, MB = 45;
const CW = PW - ML - MR; // ~519

// ===== Layout Engine =====
const pages = [[]];
let curY = PH; // will be set properly after cover header

const curPage = () => pages[pages.length - 1];

const cmdRect = (x, y, w, h, fill) => {
  curPage().push({ type: 'rect', x, y, w, h, fill });
};

const cmdText = (text, x, y, size, bold, color) => {
  curPage().push({ type: 'text', text, x, y, size, bold, color: color || NAVY });
};

const cmdLogo = (x, y) => {
  curPage().push({ type: 'logo', x, y });
};

const addV = h => { curY -= h; };

const ensureY = needed => {
  if (curY - needed < MB) {
    pages.push([]);
    curY = PH;
    addPageHeader();
  }
};

// ===== Sub-page header (all pages except cover) =====
function addPageHeader() {
  const BAR_H = 30;
  cmdRect(0, PH - BAR_H, PW, BAR_H, NAVY);
  cmdRect(0, PH - BAR_H - 4, PW, 4, PINK);
  cmdText('G2FIT NUTRICION  |  PLAN NUTRICIONAL PERSONALIZADO', ML, PH - 20, 7.5, true, WHITE);
  cmdText(N(cliente.nombre), PW - MR - 120, PH - 20, 7.5, false, [0.75, 0.82, 0.9]);
  curY = PH - BAR_H - 4 - 12;
}

// ===== Footer on each page =====
function addFooter(pageNum, totalPages) {
  const FY = 28;
  cmdRect(0, 0, PW, FY, NAVY);
  cmdText('G2FIT NUTRICION  |  Tu bienestar, nuestra mision', ML, 10, 7, false, [0.5, 0.6, 0.75]);
  cmdText('Pag. ' + pageNum + ' / ' + totalPages, PW - MR - 50, 10, 7, false, [0.5, 0.6, 0.75]);
}

// ===== COVER PAGE =====
const COVER_H = 115;
cmdRect(0, PH - COVER_H, PW, COVER_H, NAVY);
cmdRect(0, PH - COVER_H - 5, PW, 5, PINK);

// Logo centered in cover header (white background behind logo)
const LOGO_PAD = 10;
const LOGO_X_COVER = (PW - LOGO_DW) / 2;
const LOGO_Y_COVER = PH - COVER_H + (COVER_H - LOGO_DH) / 2;
cmdRect(LOGO_X_COVER - LOGO_PAD, LOGO_Y_COVER - LOGO_PAD, LOGO_DW + LOGO_PAD * 2, LOGO_DH + LOGO_PAD * 2, WHITE);
cmdLogo(LOGO_X_COVER, LOGO_Y_COVER);

curY = PH - COVER_H - 5;

// Title section
addV(30);
cmdText('PLAN NUTRICIONAL PERSONALIZADO', ML, curY, 13, true, PINK);
addV(24);
cmdText(N(cliente.nombre), ML, curY, 21, true, NAVY);
addV(14);

const objText = N(cliente.objetivo || '');
if (objText) {
  cmdText('Objetivo: ' + objText, ML, curY, 9, false, GRAY);
  addV(14);
}

// Kcal info line


// Intro text
cmdRect(ML, curY - 42, CW, 42, LIGHT_BG);
cmdRect(ML, curY - 42, 4, 42, PINK);
cmdText('Sigue este plan durante todo el mes. Esta dieta ha sido disenada especialmente', ML + 12, curY - 14, 8.5, false, NAVY);
cmdText('para ti en funcion de tus objetivos, preferencias y restricciones alimentarias.', ML + 12, curY - 26, 8.5, false, NAVY);
cmdText('Si tienes alguna duda, responde a este email.', ML + 12, curY - 38, 8.5, false, GRAY);
curY -= 42 + 20;

// Divider before days
cmdRect(ML, curY, CW, 1.5, PINK);
curY -= 20;


// ===== NOTAS DE LA NUTRICIONISTA =====
addV(8);
const NOTASH = 22;
cmdRect(ML, curY - NOTASH, CW, NOTASH, NAVY);
cmdRect(ML, curY - NOTASH, 4, NOTASH, PINK);
cmdText('NOTAS IMPORTANTES DE TU NUTRICIONISTA', ML + 10, curY - 15, 8.5, true, WHITE);
curY -= NOTASH + 6;

const notasPDF = [
  { t: 'Cafe e infusiones', l: [
    'Puedes consumir cafe solo con agua libremente, sin necesidad de especificarlo en la dieta.',
    'Infusiones y te: siempre sin azucar, miel ni otros endulzantes caloricos.'
  ]},
  { t: 'Hidratacion', l: [
    'Procura beber al menos 2 litros de agua al dia.',
    'Una buena hidratacion es clave para el metabolismo, la digestion y el rendimiento diario.'
  ]},
  { t: 'Consumo de fruta', l: [
    'Intenta consumir la fruta en la comida indicada en la dieta,',
    'ya que su distribucion esta pensada con un objetivo nutricional concreto.'
  ]},
  { t: 'Verduras', l: [
    'Puedes variar las verduras segun tus gustos; las que aparecen son una sugerencia de combinacion.',
    'Puedes aumentar la cantidad si lo necesitas: aportan saciedad, fibra y micronutrientes.'
  ]},
  { t: 'Aceite de oliva', l: [
    'Controla la cantidad de aceite al cocinar o alinnar. Aunque es saludable, aporta calorias.',
    '1 cucharadita pequenna = aprox. 5 ml | 1 cucharada sopera = aprox. 10 ml.',
    'Mide el aceite con cuchara en lugar de verterlo directamente de la botella.'
  ]},
  { t: 'Cambios puntuales en la dieta', l: [
    'Si algun dia deseas comer algo diferente, intenta cambiar el dia completo, no solo una comida.',
    'Esto ayuda a mantener el equilibrio nutricional del plan.'
  ]},
  { t: 'No saltarse comidas', l: [
    'La distribucion de comidas esta pensada para mantener la energia estable durante el dia',
    'y facilitar la adherencia a la dieta. Intenta no saltarte ninguna.'
  ]},
  { t: 'Proteinas del pan', l: [
    'La proteina del pan integral o tipo Wasa puede variarse segun tus preferencias:',
    'pavo, jamon serrano, pollo, atun u otra opcion similar.'
  ]},
  { t: 'Edulcorantes', l: [
    'Puedes utilizar edulcorante al gusto, ya que no aporta calorias significativas dentro de la dieta.'
  ]}
];

for (const nota of notasPDF) {
  const nL = nota.l.length;
  const NH = 10 + 13 + nL * 11 + 6;
  ensureY(NH + 4);
  cmdRect(ML, curY - NH, CW, NH, LIGHT_BG);
  cmdRect(ML, curY - NH, 3, NH, PINK);
  cmdText(nota.t.toUpperCase(), ML + 9, curY - 14, 7.5, true, NAVY);
  nota.l.forEach((l, i) => {
    cmdText('- ' + l, ML + 9, curY - 26 - i * 11, 7, false, GRAY);
  });
  curY -= NH + 4;
}

// ===== DAY SECTIONS =====
for (const dia of dias) {
  // Each day on its own page
  pages.push([]);
  curY = PH;
  addPageHeader();

  // Day header bar
  const DAY_H = 33;
  cmdRect(ML, curY - DAY_H, CW, DAY_H, NAVY);
  cmdRect(ML, curY - DAY_H, 5, DAY_H, PINK);
  const dayName = N(dia.nombre_dia || ('DIA ' + dia.dia)).toUpperCase();
  cmdText(dayName, ML + 14, curY - 21, 11, true, WHITE);


  curY -= DAY_H + 5;

  for (const comida of dia.comidas || []) {
    // ─── Two-column: ingredients (left) | preparation (right) ──────────────
    const ingArr = (comida.ingredientes || [])
      .map(i => N(typeof i === 'string' ? i : (i.nombre || '')));
    const prepRaw = (comida.preparacion || []).map(p => N(p));

    // Column geometry
    const CONTENT_X  = ML + 12;
    const FULL_W     = CW - 20;
    const COL_L_W    = Math.round(FULL_W * 0.50);
    const COL_GAP    = 10;
    const COL_R_X    = CONTENT_X + COL_L_W + COL_GAP;
    const COL_R_W    = FULL_W - COL_L_W - COL_GAP;
    const PREP_CHARS = Math.floor(COL_R_W / (7 * 0.52));

    // Build prep lines: label + wrapped steps
    const prepLines = [];
    if (prepRaw.length > 0) {
      prepLines.push({ text: 'PREPARACION', label: true });
      prepRaw.forEach((step, idx) => {
        const wrapped = wrapText((idx + 1) + '. ' + step, PREP_CHARS);
        wrapped.forEach(l => prepLines.push({ text: l, label: false }));
      });
    }

    const PAD      = 10;
    const TIPO_H   = 15;
    const NAME_H   = 15;
    const HEADER_H = TIPO_H + NAME_H;
    const AFTER_H  = 7;
    const LINE_H   = 11;

    const contentRows = Math.max(ingArr.length, prepLines.length, 1);
    const CARD_H     = PAD + HEADER_H + AFTER_H + contentRows * LINE_H + PAD;

    ensureY(CARD_H + 5);

    // Card background + left border
    cmdRect(ML, curY - CARD_H, CW, CARD_H, LIGHT_BG);
    cmdRect(ML, curY - CARD_H, 4, CARD_H, PINK);

    // Column separator line
    if (prepLines.length > 0) {
      const sepX   = CONTENT_X + COL_L_W + Math.floor(COL_GAP / 2);
      const sepBot = curY - CARD_H + PAD;
      const sepTop = curY - PAD - HEADER_H - 2;
      if (sepTop > sepBot) cmdRect(sepX, sepBot, 0.7, sepTop - sepBot, DIVIDER);
    }

    // Type label (pink bold)
    const tipo = N(comida.tipo || '').toUpperCase();
    cmdText(tipo, CONTENT_X, curY - PAD - TIPO_H + 3, 7, true, PINK);

    // Meal name (navy bold)
    cmdText(N(comida.nombre || ''), CONTENT_X, curY - PAD - HEADER_H + 3, 10, true, NAVY);

    // Content area Y start
    const contentTopY = curY - PAD - HEADER_H - AFTER_H;

    // Ingredients — left column, one per row with dash bullet
    ingArr.forEach((ing, i) => {
      cmdText('- ' + ing, CONTENT_X, contentTopY - i * LINE_H, 7, false, GRAY);
    });

    // Preparation — right column
    prepLines.forEach((line, i) => {
      cmdText(line.text, COL_R_X, contentTopY - i * LINE_H, 7, line.label, line.label ? PINK : GRAY);
    });

    curY -= CARD_H + 4;
  }

}

// Add footers (we'll do them after we know total pages)
const totalPages = pages.length;
for (let p = 0; p < totalPages; p++) {
  // Inject footer commands at start of page (drawn first so content is on top)
  const footerCmds = [];
  const FY = 28;
  footerCmds.push({ type: 'rect', x: 0, y: 0, w: PW, h: FY, fill: NAVY });
  footerCmds.push({ type: 'text', text: 'G2FIT NUTRICION  |  Tu bienestar, nuestra mision', x: ML, y: 10, size: 7, bold: false, color: [0.5, 0.6, 0.75] });
  footerCmds.push({ type: 'text', text: 'Pag. ' + (p + 1) + ' / ' + totalPages, x: PW - MR - 55, y: 10, size: 7, bold: false, color: [0.5, 0.6, 0.75] });
  pages[p].unshift(...footerCmds);
}

// ===== PDF GENERATION =====
const nP = pages.length;
const ID_CAT   = 1, ID_PAGES = 2;
const ID_PAGE  = i => 3 + i;
const ID_CONT  = i => 3 + nP + i;
const ID_FREG  = 3 + 2*nP;
const ID_FBOLD = 4 + 2*nP;
const ID_LOGO  = 5 + 2*nP;
const NOBJ     = 6 + 2*nP;

const buf = [];
let pos = 0;
const offsets = {};

const WB = s => { buf.push(s); pos += s.length; };

const writeObj = (id, dict) => {
  offsets[id] = pos;
  WB(`${id} 0 obj\n${dict}\nendobj\n`);
};

const writeStream = (id, stream) => {
  offsets[id] = pos;
  WB(`${id} 0 obj\n<</Length ${stream.length}>>\nstream\n${stream}\nendstream\nendobj\n`);
};

const writeStreamDict = (id, extraDict, stream) => {
  offsets[id] = pos;
  WB(`${id} 0 obj\n<<${extraDict} /Length ${stream.length}>>\nstream\n${stream}\nendstream\nendobj\n`);
};

WB('%PDF-1.4\n');
writeObj(ID_CAT,   `<</Type /Catalog /Pages ${ID_PAGES} 0 R>>`);
const kids = Array.from({length:nP}, (_,i) => `${ID_PAGE(i)} 0 R`).join(' ');
writeObj(ID_PAGES, `<</Type /Pages /Kids [${kids}] /Count ${nP}>>`);

for (let p = 0; p < nP; p++) {
  writeObj(ID_PAGE(p),
    `<</Type /Page /Parent ${ID_PAGES} 0 R /MediaBox [0 0 ${PW} ${PH}] ` +
    `/Contents ${ID_CONT(p)} 0 R ` +
    `/Resources <</Font <</F1 ${ID_FREG} 0 R /F2 ${ID_FBOLD} 0 R>> ` +
    `/XObject <</Logo ${ID_LOGO} 0 R>>>>>>`
  );
}

// Watermark coords
const WM_CX = PW / 2, WM_CY = PH / 2;
const WM_HALF = 150;
const WMX1 = (WM_CX - WM_HALF * 0.7071).toFixed(2);
const WMY1 = (WM_CY - WM_HALF * 0.7071).toFixed(2);
const WMX2 = (WM_CX - WM_HALF * 0.7071 - 80).toFixed(2);
const WMY2 = (WM_CY - WM_HALF * 0.7071 + 240).toFixed(2);

for (let p = 0; p < nP; p++) {
  let stream = '';

  // Watermark
  stream += `BT\n/F2 38 Tf\n0.88 0.88 0.88 rg\n`;
  stream += `0.7071 0.7071 -0.7071 0.7071 ${WMX1} ${WMY1} Tm\n(G2FIT CONFIDENCIAL) Tj\n`;
  stream += `0.7071 0.7071 -0.7071 0.7071 ${WMX2} ${WMY2} Tm\n(G2FIT CONFIDENCIAL) Tj\nET\n`;

  // Draw commands
  for (const cmd of pages[p]) {
    if (cmd.type === 'rect') {
      const [r,g,b] = cmd.fill;
      stream += `${r.toFixed(3)} ${g.toFixed(3)} ${b.toFixed(3)} rg\n`;
      stream += `${cmd.x.toFixed(2)} ${cmd.y.toFixed(2)} ${cmd.w.toFixed(2)} ${cmd.h.toFixed(2)} re f\n`;
    } else if (cmd.type === 'text') {
      const f = cmd.bold ? 'F2' : 'F1';
      const txt = E(cmd.text || ' ');
      const [r,g,b] = cmd.color || [0,0,0];
      stream += `BT\n/${f} ${cmd.size} Tf\n`;
      stream += `${r.toFixed(3)} ${g.toFixed(3)} ${b.toFixed(3)} rg\n`;
      stream += `1 0 0 1 ${cmd.x.toFixed(2)} ${cmd.y.toFixed(2)} Tm\n(${txt}) Tj\nET\n`;
    } else if (cmd.type === 'logo') {
      stream += `q\n${LOGO_DW} 0 0 ${LOGO_DH} ${cmd.x.toFixed(2)} ${cmd.y.toFixed(2)} cm\n/Logo Do\nQ\n`;
    }
  }

  writeStream(ID_CONT(p), stream);
}

writeObj(ID_FREG,  `<</Type /Font /Subtype /Type1 /BaseFont /Helvetica /Encoding /WinAnsiEncoding>>`);
writeObj(ID_FBOLD, `<</Type /Font /Subtype /Type1 /BaseFont /Helvetica-Bold /Encoding /WinAnsiEncoding>>`);

// Logo XObject
const logoBytes = Buffer.from(LOGO_B64, 'base64');
const logoHex = logoBytes.toString('hex') + '>';
writeStreamDict(ID_LOGO,
  `/Type /XObject /Subtype /Image /Width ${LOGO_W} /Height ${LOGO_H}` +
  ` /ColorSpace /DeviceRGB /BitsPerComponent 8` +
  ` /Filter [/ASCIIHexDecode /FlateDecode]`,
  logoHex
);

const xrefPos = pos;
WB(`xref\n0 ${NOBJ}\n`);
WB('0000000000 65535 f \n');
for (let i = 1; i < NOBJ; i++) {
  WB((offsets[i]||0).toString().padStart(10,'0') + ' 00000 n \n');
}
WB(`trailer\n<</Size ${NOBJ} /Root ${ID_CAT} 0 R>>\nstartxref\n${xrefPos}\n%%EOF\n`);

const pdfString = buf.join('');
const base64 = Buffer.from(pdfString, 'binary').toString('base64');

const nombreArchivo = 'plan_nutricional_' + N(cliente.nombre).replace(/\s+/g,'_').toLowerCase() + '.pdf';


