// === LISTA DE LA COMPRA PDF ===
const listaIngredientes = {};
for (const dia of dias) {
  for (const comida of (dia.comidas || [])) {
    for (const ing of (comida.ingredientes || [])) {
      const textoIng = typeof ing === 'string' ? ing : (ing.nombre || '');
      if (!textoIng) continue;
      const match = textoIng.match(/^([\d.,]+\s*(?:g|kg|ml|l|cda|cdta|taza|unidades?|uds?|piezas?|rebanadas?)?)[\s-]+(.+)$/i);
      let cantidad = '';
      let nombreIng = textoIng;
      if (match) { cantidad = match[1].trim(); nombreIng = match[2].trim().toLowerCase(); }
      if (!listaIngredientes[nombreIng]) listaIngredientes[nombreIng] = [];
      if (cantidad) listaIngredientes[nombreIng].push(cantidad);
    }
  }
}

const CATMAP = {
  'Proteinas': ['pollo','pechuga','ternera','cerdo','salmon','atun','sardina','dorada','merluza','bacalao','gambas','langostino','mejillon','huevo','tofu','tempeh'],
  'Lacteos': ['leche','yogur','queso','requesón','kefir','mantequilla','nata','feta','mozzarella'],
  'Verduras': ['tomate','lechuga','espinaca','zanahoria','pepino','pimiento','cebolla','ajo','calabacin','berenjena','brocoli','coliflor','apio','puerro','esparragos','champiñon','remolacha'],
  'Frutas': ['manzana','naranja','platano','pera','fresa','kiwi','melocoton','sandia','melon','mango','arandano','frambuesa'],
  'Carbohidratos': ['arroz','pasta','pan','patata','avena','quinoa','cuscus','harina','lenteja','garbanzo','alubia'],
  'Grasas': ['aceite','oliva','aguacate','nuez','almendra','piñon','sesamo','chia'],
  'Otros': []
};
function getcat(n) {
  for (const [cat, kws] of Object.entries(CATMAP)) {
    if (cat === 'Otros') continue;
    if (kws.some(k => n.includes(k))) return cat;
  }
  return 'Otros';
}
const porCat = {};
for (const [ing, cants] of Object.entries(listaIngredientes)) {
  const cat = getcat(ing);
  if (!porCat[cat]) porCat[cat] = [];
  porCat[cat].push({ ing, cants: cants.join(' + ') });
}

// Build shopping list PDF
const sPages = [[]];
let sCurY = 841.89 - 38;
const SML = 38, SCW = 519.28, SNAVY = [0.059,0.086,0.165], SPINK = [0.984,0.373,0.671];
const SWHITE = [1,1,1], SGRAY = [0.4,0.4,0.4], SLBG = [0.97,0.97,0.99];

function sCmd(c) { sPages[sPages.length-1].push(c); }
function sNewPage() { sPages.push([]); sCurY = 841.89 - 38 - 60; }
function sEnsureY(h) { if (sCurY - h < 60) sNewPage(); }
function sRect(x,y,w,h,rgb) { sCmd(rgb[0].toFixed(3)+' '+rgb[1].toFixed(3)+' '+rgb[2].toFixed(3)+' rg '+x.toFixed(2)+' '+(y-h).toFixed(2)+' '+w.toFixed(2)+' '+h.toFixed(2)+' re f'); }
function sTxt(t,x,y,sz,bold,rgb) { sCmd('BT '+(bold?'/F2':'/F1')+' '+sz+' Tf '+rgb[0].toFixed(3)+' '+rgb[1].toFixed(3)+' '+rgb[2].toFixed(3)+' rg '+x.toFixed(2)+' '+y.toFixed(2)+' Td ('+t.replace(/[()\\]/g,'\\$&')+') Tj ET'); }

// Header
sRect(0, 841.89, 595.28, 80, SNAVY);
sRect(0, 841.89, 5, 80, SPINK);
sTxt('LISTA DE LA COMPRA SEMANAL', SML+10, 841.89-35, 14, true, SWHITE);
sTxt(N(cliente.nombre ? 'Plan de '+cliente.nombre : 'Plan G2Fit Nutricion'), SML+10, 841.89-55, 9, false, [0.8,0.8,0.9]);
sCurY = 841.89 - 80 - 14;

const catOrder = ['Proteinas','Lacteos','Verduras','Frutas','Carbohidratos','Grasas','Otros'];
for (const cat of catOrder) {
  const items = porCat[cat];
  if (!items || !items.length) continue;
  items.sort((a,b) => a.ing.localeCompare(b.ing));
  const totalH = 24 + items.length * 16 + 8;
  sEnsureY(totalH + 10);
  sRect(SML, sCurY, SCW, 24, SNAVY);
  sRect(SML, sCurY, 4, 24, SPINK);
  sTxt(N(cat).toUpperCase(), SML+12, sCurY-16, 8.5, true, SWHITE);
  sCurY -= 24;
  items.forEach((item, i) => {
    sRect(SML, sCurY, SCW, 16, i%2===0 ? SLBG : SWHITE);
    sRect(SML+8, sCurY-13, 10, 10, [0.85,0.85,0.9]);
    sTxt(N(item.ing), SML+24, sCurY-11, 8, false, [0.1,0.1,0.2]);
    if (item.cants) sTxt(N(item.cants), SML+SCW-130, sCurY-11, 7.5, false, SGRAY);
    sCurY -= 16;
  });
  sCurY -= 8;
}

// Compile shopping PDF
const sParts = ['%PDF-1.4\n'];
const sOffsets = [];
let sON = 0;
function sObj(c) { sON++; sOffsets.push(sParts.join('').length); sParts.push(sON+' 0 obj\n'+c+'\nendobj\n'); return sON; }
sObj('<< /Type /Catalog /Pages 2 0 R >>');
sON++; sOffsets.push(0); sParts.push('');
const sPNums = [];
for (const pg of sPages) {
  const sc = pg.join('\n');
  const slen = sObj('<< /Length '+sc.length+' >>\nstream\n'+sc+'\nendstream');
  sPNums.push(sObj('<< /Type /Page /Parent 2 0 R /MediaBox [0 0 595.28 841.89] /Contents '+slen+' 0 R /Resources << /Font << /F1 << /Type /Font /Subtype /Type1 /BaseFont /Helvetica >> /F2 << /Type /Font /Subtype /Type1 /BaseFont /Helvetica-Bold >> >> >> >>'));
}
const sKids = sPNums.map(n => n+' 0 R').join(' ');
const sPagesOff = sParts.join('').length;
sOffsets[1] = sPagesOff;
sParts[2] = '2 0 obj\n<< /Type /Pages /Kids ['+sKids+'] /Count '+sPNums.length+' >>\nendobj\n';
const sXrefPos = sParts.join('').length;
let sXref = 'xref\n0 '+(sON+1)+'\n0000000000 65535 f \n';
for (const o of sOffsets) sXref += String(o).padStart(10,'0')+' 00000 n \n';
sParts.push(sXref+'trailer\n<< /Size '+(sON+1)+' /Root 1 0 R >>\nstartxref\n'+sXrefPos+'\n%%EOF');
const shoppingBase64 = Buffer.from(sParts.join(''), 'binary').toString('base64');
const nombreLista = 'lista_compra_'+(N(cliente.nombre||'semanal').toLowerCase().replace(/\s+/g,'_'))+'.pdf';

return [{
  json: {
    cliente_email: cliente.email,
    cliente_nombre: N(cliente.nombre),
    dieta_id: dieta.id,
    nombre_archivo: nombreArchivo,
    nombre_lista: nombreLista,
    html_email: htmlEmail
  },
  binary: {
    data: {
      data: base64,
      mimeType: 'application/pdf',
      fileName: nombreArchivo,
      fileExtension: 'pdf'
    },
    lista_compra: {
      data: shoppingBase64,
      mimeType: 'application/pdf',
      fileName: nombreLista,
      fileExtension: 'pdf'
    }
  }
}];
